8cfcd351-679a-4d41-83b2-d933741259c5	45bd6d0e-e9d6-4a1a-ae90-f5fbbcbf5682	60207503-7411-489d-8803-5fb21ec6d1cb	{"ar": "غسالة ملابس توشيبا 13 كجم SDD انفرتر سيلفر AEW-DC1300SUP(SS)", "en": "غسالة ملابس توشيبا 13 كجم SDD انفرتر سيلفر AEW-DC1300SUP(SS)"}	{"ar": "<p style=\\"text-align:right;\\">غسالة توشيبا تحميل علوي</p><p style=\\"text-align:right;\\">سعة الغسالة : 13 كجم</p><p style=\\"text-align:right;\\">موتور الغسالة انفرتر موفر للطاقة و مانع للاهتزاز والضوضاء</p><p style=\\"text-align:right;\\">لون جسم الغسالة : سيلفر</p><p style=\\"text-align:right;\\">لون الجزء العلوي من الغسالة : سيلفر × كروم</p><p style=\\"text-align:right;\\">مزودة بطلمبة لصرف المياه</p><p style=\\"text-align:right;\\">مزودة بمدخلين للمياه ( بارد / ساخن )</p><p style=\\"text-align:right;\\">مزودة بفلتر نسالة بتصميم جديد وعمر أطول</p><p style=\\"text-align:right;\\">مصنوعة من مواد عالية الجودة ومقاومة للصدأ</p><p style=\\"text-align:right;\\">تحكم كامل لوظائف التشغيل بواسطة نظام كمبيوتر ذكي</p><p style=\\"text-align:right;\\">خواص الغسالة :-</p><p style=\\"text-align:right;\\">دورة الغسيل الأعتيادي</p><p style=\\"text-align:right;\\">دورة الذاكرة</p><p style=\\"text-align:right;\\">دورة غسيل البطاطين</p><p style=\\"text-align:right;\\">دورة الغسيل اللطيف</p><p style=\\"text-align:right;\\">دورة النقع (حتى 60 دقيقة)</p><p style=\\"text-align:right;\\">دورة الغسيل الثقيل</p><p style=\\"text-align:right;\\">دورة لإعطاء رائحة عطرة للملابس</p><p style=\\"text-align:right;\\">دورة الغسيل السريع</p><p style=\\"text-align:right;\\">دورة تنظيف حوض الغسيل</p><p style=\\"text-align:right;\\">خاصية قفل ضد عبث الاطفال لحمايتهم عن طريق القفل المحكم لغطاء الغسالة</p><p style=\\"text-align:right;\\">خاصية تجفيف الدوران السريع عن طريق مدخل هواء دائري أثناء دورة العصر الفائق</p><p style=\\"text-align:right;\\">خاصية تجفيف الحوض</p><p style=\\"text-align:right;\\">خاصية الغسيل المكثف التمهيدي</p><p style=\\"text-align:right;\\">إمكانية التحكم فى قوة تدفق المياه أثناء التشغيل لتناسب جميع أنواع الأقمشة والاتساخات</p><p style=\\"text-align:right;\\">إمكانية تحديد مستوى المياه بالغسالة أوتوماتيكياً ليتناسب مع كمية الغسيل</p><p style=\\"text-align:right;\\">تصميم مميز للحلة الداخلية :</p><p style=\\"text-align:right;\\">يتميز سطح الحلة الداخلية للغسالة بتصميم دقيق</p><p style=\\"text-align:right;\\">على شكل نجوم كريستالية بارزة وهو مستوحى من</p><p style=\\"text-align:right;\\">لوح الغسيل المستخدم قديماً في إزالة البقع الصعبة</p><p style=\\"text-align:right;\\">مما يضمن تحقيق النظافة المثالية بإزالة جميع أنواع</p><p style=\\"text-align:right;\\">البقع مع توفير افضل حماية للملابس الرقيقة من التلف</p><p style=\\"text-align:right;\\">تصميم مبتكر لمروحة الغسالة :</p><p style=\\"text-align:right;\\">المروحة ذات تصميم جديد بعزم أقوى لدوران المياه مع الغسيل مما يحقق نظافة أعلى للغسيل ويمنع التشابك</p><p style=\\"text-align:right;\\">تعمل الغسالة بخاصية Hydro twin power :</p><p style=\\"text-align:right;\\">هي شلالات تعيد سحب وضخ المياه اثناء الغسيل لرفع كفاءة المسحوق والتغلغل مع المياه والملابس</p><p style=\\"text-align:right;\\">غسالة اقتصادية موفرة للطاقة :-</p><p style=\\"text-align:right;\\">- يتم فصل التيار أوتوماتيكياً عن الغساله بعد 15 ثانيه من إنتهاء دورة الغسيل وذلك لتوفير استهلاك الكهرباء</p><p style=\\"text-align:right;\\">- لا تستهلك الغسالة طاقة كهربائية أثناء وضع الاستعداد</p><p style=\\"text-align:right;\\">- شطف الغسيل بكمية مياه أقل</p><p style=\\"text-align:right;\\">- تستكمل الغسالة دورة الغسيل تلقائياً فى حالة عودة التيار الكهربائي بعد إنقطاعه</p><p style=\\"text-align:right;\\">أبعاد الغسالة (مم) :-</p><p style=\\"text-align:right;\\">العرض × الارتفاع × العمق : 645 × 1088 × 685</p><p style=\\"text-align:right;\\">وزن الغسالة :-</p><p style=\\"text-align:right;\\">الوزن الصافي : 49 كجم</p><p style=\\"text-align:right;\\">الوزن الاجمالي : 55 كجم</p><p style=\\"text-align:right;\\">بلد المنشأ : مصر</p><p style=\\"text-align:right;\\">الضمان : 5 سنوات ضمان مجاني شامل</p>", "en": "<p style=\\"text-align:right;\\">غسالة توشيبا تحميل علوي</p><p style=\\"text-align:right;\\">سعة الغسالة : 13 كجم</p><p style=\\"text-align:right;\\">موتور الغسالة انفرتر موفر للطاقة و مانع للاهتزاز والضوضاء</p><p style=\\"text-align:right;\\">لون جسم الغسالة : سيلفر</p><p style=\\"text-align:right;\\">لون الجزء العلوي من الغسالة : سيلفر × كروم</p><p style=\\"text-align:right;\\">مزودة بطلمبة لصرف المياه</p><p style=\\"text-align:right;\\">مزودة بمدخلين للمياه ( بارد / ساخن )</p><p style=\\"text-align:right;\\">مزودة بفلتر نسالة بتصميم جديد وعمر أطول</p><p style=\\"text-align:right;\\">مصنوعة من مواد عالية الجودة ومقاومة للصدأ</p><p style=\\"text-align:right;\\">تحكم كامل لوظائف التشغيل بواسطة نظام كمبيوتر ذكي</p><p style=\\"text-align:right;\\">خواص الغسالة :-</p><p style=\\"text-align:right;\\">دورة الغسيل الأعتيادي</p><p style=\\"text-align:right;\\">دورة الذاكرة</p><p style=\\"text-align:right;\\">دورة غسيل البطاطين</p><p style=\\"text-align:right;\\">دورة الغسيل اللطيف</p><p style=\\"text-align:right;\\">دورة النقع (حتى 60 دقيقة)</p><p style=\\"text-align:right;\\">دورة الغسيل الثقيل</p><p style=\\"text-align:right;\\">دورة لإعطاء رائحة عطرة للملابس</p><p style=\\"text-align:right;\\">دورة الغسيل السريع</p><p style=\\"text-align:right;\\">دورة تنظيف حوض الغسيل</p><p style=\\"text-align:right;\\">خاصية قفل ضد عبث الاطفال لحمايتهم عن طريق القفل المحكم لغطاء الغسالة</p><p style=\\"text-align:right;\\">خاصية تجفيف الدوران السريع عن طريق مدخل هواء دائري أثناء دورة العصر الفائق</p><p style=\\"text-align:right;\\">خاصية تجفيف الحوض</p><p style=\\"text-align:right;\\">خاصية الغسيل المكثف التمهيدي</p><p style=\\"text-align:right;\\">إمكانية التحكم فى قوة تدفق المياه أثناء التشغيل لتناسب جميع أنواع الأقمشة والاتساخات</p><p style=\\"text-align:right;\\">إمكانية تحديد مستوى المياه بالغسالة أوتوماتيكياً ليتناسب مع كمية الغسيل</p><p style=\\"text-align:right;\\">تصميم مميز للحلة الداخلية :</p><p style=\\"text-align:right;\\">يتميز سطح الحلة الداخلية للغسالة بتصميم دقيق</p><p style=\\"text-align:right;\\">على شكل نجوم كريستالية بارزة وهو مستوحى من</p><p style=\\"text-align:right;\\">لوح الغسيل المستخدم قديماً في إزالة البقع الصعبة</p><p style=\\"text-align:right;\\">مما يضمن تحقيق النظافة المثالية بإزالة جميع أنواع</p><p style=\\"text-align:right;\\">البقع مع توفير افضل حماية للملابس الرقيقة من التلف</p><p style=\\"text-align:right;\\">تصميم مبتكر لمروحة الغسالة :</p><p style=\\"text-align:right;\\">المروحة ذات تصميم جديد بعزم أقوى لدوران المياه مع الغسيل مما يحقق نظافة أعلى للغسيل ويمنع التشابك</p><p style=\\"text-align:right;\\">تعمل الغسالة بخاصية Hydro twin power :</p><p style=\\"text-align:right;\\">هي شلالات تعيد سحب وضخ المياه اثناء الغسيل لرفع كفاءة المسحوق والتغلغل مع المياه والملابس</p><p style=\\"text-align:right;\\">غسالة اقتصادية موفرة للطاقة :-</p><p style=\\"text-align:right;\\">- يتم فصل التيار أوتوماتيكياً عن الغساله بعد 15 ثانيه من إنتهاء دورة الغسيل وذلك لتوفير استهلاك الكهرباء</p><p style=\\"text-align:right;\\">- لا تستهلك الغسالة طاقة كهربائية أثناء وضع الاستعداد</p><p style=\\"text-align:right;\\">- شطف الغسيل بكمية مياه أقل</p><p style=\\"text-align:right;\\">- تستكمل الغسالة دورة الغسيل تلقائياً فى حالة عودة التيار الكهربائي بعد إنقطاعه</p><p style=\\"text-align:right;\\">أبعاد الغسالة (مم) :-</p><p style=\\"text-align:right;\\">العرض × الارتفاع × العمق : 645 × 1088 × 685</p><p style=\\"text-align:right;\\">وزن الغسالة :-</p><p style=\\"text-align:right;\\">الوزن الصافي : 49 كجم</p><p style=\\"text-align:right;\\">الوزن الاجمالي : 55 كجم</p><p style=\\"text-align:right;\\">بلد المنشأ : مصر</p><p style=\\"text-align:right;\\">الضمان : 5 سنوات ضمان مجاني شامل</p>"}	غسالة-ملابس-توشيبا-13-كجم-sdd-انفرتر-سيلفر-aew-dc1300sup-ss-3061	21350.00	\N	\N	\N	0	5	active	f	0	2026-06-14 06:34:17.353	2026-06-14 06:42:04.435	\N	\N
